    fn tokenToSymbol(_: *Parser, token: Token) u16 {
        return switch (token.cat) {
            .@"eof" => 1,
            .@"semi" => 17,
            .@"and_and" => 18,
            .@"or_or" => 19,
            .@"amp" => 20,
            .@"pipe" => 23,
            .@"lparen" => 24,
            .@"rparen" => 25,
            .@"ident" => 29,
            .@"integer" => 30,
            .@"string_sq" => 31,
            .@"string_dq" => 32,
            .@"lt" => 33,
            .@"fd_lt" => 34,
            .@"gt" => 35,
